package main

import (
	"net"
	"strings"
)

type User struct {
	Username string
	Address  string
	Channel  chan string
	conn     net.Conn
	server   *Server
}

// 创建一个用户的API
func NewUser(conn net.Conn, server *Server) *User {
	user := &User{
		Username: conn.RemoteAddr().String(),
		Address:  conn.RemoteAddr().String(),
		Channel:  make(chan string),
		conn:     conn,
		server:   server,
	}
	go user.ListenMessage()
	return user
}

func (u *User) Online() {
	// 广播当前用户上线
	// server.BroadCast(u, "已上线")
	//用户上线
	u.server.maplock.Lock()
	u.server.OnlineMap[u.Username] = u
	u.server.maplock.Unlock()

	//广播当前用户上线
	u.server.BroadCast(u, "已上线")
}

func (u *User) Offline() {
	// 广播当前用户下线
	// server.BroadCast(u, "已下线")

	//用户下线
	u.server.maplock.Lock()
	delete(u.server.OnlineMap, u.Username)
	u.server.maplock.Unlock()

	//广播当前用户下线
	u.server.BroadCast(u, "已下线")
}

func (u *User) ReName(newName string) {
	// 用户修改用户名
	u.server.maplock.Lock()
	delete(u.server.OnlineMap, u.Username)
	u.Username = newName
	u.server.OnlineMap[newName] = u
	u.server.maplock.Unlock()

	// 广播当前用户修改用户名
	u.server.BroadCast(u, "您已修改用户名为："+newName)
}

func (u *User) SendMsg(msg string) {
	u.conn.Write([]byte(msg + "\n"))
}

// 用户消息处理业务
func (u *User) DoMsg(msg string) {
	if msg == "who" {
		//查询在线用户
		u.server.maplock.RLock()
		for _, user := range u.server.OnlineMap {
			onlineMsg := "[" + user.Username + "]: " + "在线"
			u.SendMsg(onlineMsg)
		}
		u.server.maplock.RUnlock()
	} else if len(msg) > 7 && msg[:7] == "rename|" {
		//修改用户名
		// 使用Split方法以"|"为分隔符分割字符串，并取第二个元素作为新用户名
		newName := strings.Split(msg, "|")[1]
		//防止名字重复
		_, ok := u.server.OnlineMap[newName]
		if ok {
			u.SendMsg("当前用户名已存在")
			return
		} else {
			u.ReName(newName)
			u.SendMsg("修改用户名成功")
		}
	} else {
		// 将消息广播给其他在线用户
		u.server.BroadCast(u, msg)
	}

}

// 监听用户channel的方法
func (u *User) ListenMessage() {
	for {
		msg := <-u.Channel
		u.conn.Write([]byte(msg + "\n"))
	}
}

